import { useEffect, useState } from "react";
import { Container, Card, Button, Alert, Form, Spinner, Table } from "react-bootstrap";
import { useNavigate, useParams } from "react-router-dom";
import { getOrderDetail } from "../services/orderService";
import { createPaymentIntent, processPayment } from "../services/paymentService";

function PaymentPage() {
  const { orderId } = useParams();
  const navigate = useNavigate();

  const [order, setOrder] = useState(null);
  const [items, setItems] = useState([]);
  const [tickets, setTickets] = useState([]);
  const [walletAddress, setWalletAddress] = useState("");
  const [paymentIntentId, setPaymentIntentId] = useState("");
  const [clientSecret, setClientSecret] = useState("");
  const [loading, setLoading] = useState(true);
  const [creatingIntent, setCreatingIntent] = useState(false);
  const [paying, setPaying] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  useEffect(() => {
    const fetchOrder = async () => {
      try {
        setLoading(true);
        setError("");

        const response = await getOrderDetail(orderId);

        if (response.data?.success) {
          setOrder(response.data.data.order);
          setItems(response.data.data.items || []);
          setTickets(response.data.data.tickets || []);
        } else {
          setError("Không lấy được thông tin đơn hàng");
        }
      } catch (err) {
        setError(err.response?.data?.message || "Lỗi khi tải đơn hàng");
      } finally {
        setLoading(false);
      }
    };

    fetchOrder();
  }, [orderId]);

  const handleCreateIntent = async () => {
    try {
      setCreatingIntent(true);
      setError("");
      setSuccess("");

      const response = await createPaymentIntent(orderId);

      if (response.data?.success) {
        setPaymentIntentId(response.data.data.paymentIntentId);
        setClientSecret(response.data.data.clientSecret);
        setSuccess("Đã tạo yêu cầu thanh toán");
      } else {
        setError(response.data?.message || "Không tạo được thanh toán");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Lỗi khi tạo payment intent");
    } finally {
      setCreatingIntent(false);
    }
  };

  const handleProcessPayment = async () => {
    try {
      if (!paymentIntentId) {
        setError("Bạn cần tạo yêu cầu thanh toán trước");
        return;
      }

      if (!walletAddress.trim()) {
        setError("Vui lòng nhập địa chỉ ví");
        return;
      }

      setPaying(true);
      setError("");
      setSuccess("");

      const response = await processPayment({
        orderId,
        paymentIntentId,
        walletAddress,
      });

      if (response.data?.success) {
        setSuccess("Thanh toán thành công và đã mint NFT vé");
      } else {
        setError(response.data?.message || "Thanh toán thất bại");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Lỗi khi xử lý thanh toán");
    } finally {
      setPaying(false);
    }
  };

  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ minHeight: "70vh" }}>
        <Spinner animation="border" />
      </div>
    );
  }

  if (!order) {
    return (
      <Container className="py-5 text-center">
        <h3>Không tìm thấy đơn hàng</h3>
      </Container>
    );
  }

  return (
    <Container className="py-5">
      <Card className="shadow-sm border-0 rounded-4">
        <Card.Body className="p-4">
          <h2 className="mb-4">Thanh toán đơn hàng</h2>

          {error && <Alert variant="danger">{error}</Alert>}
          {success && <Alert variant="success">{success}</Alert>}

          <div className="mb-4">
            <p><strong>Mã đơn:</strong> {order.order_code}</p>
            <p><strong>Tổng tiền:</strong> {Number(order.total_amount).toLocaleString("vi-VN")} VND</p>
            <p><strong>Trạng thái đơn:</strong> {order.order_status}</p>
            <p><strong>Trạng thái thanh toán:</strong> {order.payment_status}</p>
          </div>

          <h4 className="mb-3">Chi tiết vé</h4>
          <Table bordered hover responsive>
            <thead>
              <tr>
                <th>Loại vé</th>
                <th>Số lượng</th>
                <th>Đơn giá</th>
                <th>Thành tiền</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item.id}>
                  <td>{item.ticket_type_name}</td>
                  <td>{item.quantity}</td>
                  <td>{Number(item.unit_price).toLocaleString("vi-VN")} VND</td>
                  <td>{Number(item.subtotal).toLocaleString("vi-VN")} VND</td>
                </tr>
              ))}
            </tbody>
          </Table>

          <Form.Group className="mb-3">
            <Form.Label>Địa chỉ ví nhận NFT</Form.Label>
            <Form.Control
              type="text"
              placeholder="Nhập ví Metamask của bạn"
              value={walletAddress}
              onChange={(e) => setWalletAddress(e.target.value)}
            />
          </Form.Group>

          {paymentIntentId && (
            <Alert variant="info">
              <div><strong>Payment Intent ID:</strong> {paymentIntentId}</div>
              <div><strong>Client Secret:</strong> {clientSecret}</div>
            </Alert>
          )}

          <div className="d-flex gap-3">
            <Button variant="outline-dark" onClick={handleCreateIntent} disabled={creatingIntent}>
              {creatingIntent ? "Đang tạo..." : "Tạo yêu cầu thanh toán"}
            </Button>

            <Button variant="dark" onClick={handleProcessPayment} disabled={paying}>
              {paying ? "Đang thanh toán..." : "Thanh toán ngay"}
            </Button>

            <Button variant="secondary" onClick={() => navigate("/home")}>
              Về trang chủ
            </Button>
          </div>
        </Card.Body>
      </Card>
    </Container>
  );
}

export default PaymentPage;
